const checkpoints = [];

const treatments = JSON.parse(localStorage.getItem('treatments') || '[]');
const appointments = JSON.parse(localStorage.getItem('appointment_requests') || '[]');

function getBasePrice(t) {
  if (!t) return null;
  if (typeof t.price_min === 'number') return t.price_min;
  if (typeof t.price === 'number') return t.price;
  if (typeof t.price_per_unit === 'number') return t.price_per_unit;
  return null;
}

function durationOverlaps60to90(t) {
  if (!t) return false;
  const min = (typeof t.duration_minutes_min === 'number') ? t.duration_minutes_min : t.duration_minutes_max;
  const max = (typeof t.duration_minutes_max === 'number') ? t.duration_minutes_max : t.duration_minutes_min;
  if (min == null && max == null) return false;
  const effMin = (min != null ? min : max);
  const effMax = (max != null ? max : min);
  if (effMin == null || effMax == null) return false;
  // Overlap between [effMin, effMax] and [60, 90]
  return effMin <= 90 && effMax >= 60;
}

// Find all qualifying whitening treatments
const qualifyingTreatments = treatments.filter(t => {
  if (!t || t.treatment_type !== 'teeth_whitening' || t.delivery_method !== 'in_office') return false;
  const basePrice = getBasePrice(t);
  if (basePrice == null || basePrice >= 400) return false;
  if (!durationOverlaps60to90(t)) return false;
  return true;
});

let cheapestTreatment = null;
let cheapestBasePrice = null;
if (qualifyingTreatments.length > 0) {
  qualifyingTreatments.forEach(t => {
    const bp = getBasePrice(t);
    if (bp == null) return;
    if (cheapestBasePrice == null || bp < cheapestBasePrice) {
      cheapestBasePrice = bp;
      cheapestTreatment = t;
    }
  });
}

// Appointments for the cheapest qualifying treatment that also satisfy all treatment criteria
const cheapestAppointments = appointments.filter(a => {
  if (!a || !cheapestTreatment) return false;
  if (a.treatment_id !== cheapestTreatment.id) return false;
  const t = treatments.find(tt => tt.id === a.treatment_id);
  if (!t) return false;
  const basePrice = getBasePrice(t);
  if (basePrice == null) return false;
  if (t.treatment_type !== 'teeth_whitening' || t.delivery_method !== 'in_office') return false;
  if (basePrice >= 400) return false;
  if (!durationOverlaps60to90(t)) return false;
  // Ensure this treatment is indeed the cheapest among all qualifying
  return cheapestBasePrice != null && Math.abs(basePrice - cheapestBasePrice) < 1e-6;
});

// CP1 (0.4): At least one appointment tied to the cheapest qualifying in-office whitening under $400 with 60–90 min duration
checkpoints.push({ passed: cheapestAppointments.length > 0, weight: 0.4 });

// CP2 (0.3): Among those, at least one appointment requested on a Thursday at 3:00 PM
const hasThursday3pm = cheapestAppointments.some(a => {
  if (!a || !a.requested_datetime) return false;
  const dt = new Date(a.requested_datetime);
  if (isNaN(dt.getTime())) return false;
  const day = dt.getDay(); // 4 = Thursday
  const hour = dt.getHours();
  const minute = dt.getMinutes();
  return day === 4 && hour === 15 && minute === 0;
});
checkpoints.push({ passed: hasThursday3pm, weight: 0.3 });

// CP3 (0.3): Among those, at least one is marked as a new patient
const hasNewPatient = cheapestAppointments.some(a => a && a.patient_type === 'new_patient');
checkpoints.push({ passed: hasNewPatient, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const treatments = JSON.parse(localStorage.getItem('treatments') || '[]');
const savedPlans = JSON.parse(localStorage.getItem('saved_financing_plans') || '[]');
const apps = JSON.parse(localStorage.getItem('financing_applications') || '[]');

function getPricePerUnit(t) {
  if (!t) return null;
  if (typeof t.price_per_unit === 'number') return t.price_per_unit;
  if (typeof t.price === 'number') return t.price;
  if (typeof t.price_min === 'number') return t.price_min;
  return null;
}

const veneerPerTooth = treatments.filter(t => t && t.treatment_type === 'veneers' && t.pricing_unit === 'per_tooth' && (t.veneer_material === 'porcelain' || t.veneer_material === 'composite'));

let porcelainMinTotal = null;
let compositeMinTotal = null;

veneerPerTooth.forEach(t => {
  const ppu = getPricePerUnit(t);
  if (ppu == null) return;
  const total = ppu * 4;
  if (t.veneer_material === 'porcelain') {
    if (porcelainMinTotal == null || total < porcelainMinTotal) porcelainMinTotal = total;
  } else if (t.veneer_material === 'composite') {
    if (compositeMinTotal == null || total < compositeMinTotal) compositeMinTotal = total;
  }
});

let chosenMaterial = null;
let chosenTotalCost = null;

if (compositeMinTotal != null && compositeMinTotal <= 3000) {
  if (porcelainMinTotal == null || porcelainMinTotal > 3000 || compositeMinTotal <= porcelainMinTotal) {
    chosenMaterial = 'composite';
    chosenTotalCost = compositeMinTotal;
  }
}
if (!chosenMaterial && porcelainMinTotal != null && porcelainMinTotal <= 3000) {
  chosenMaterial = 'porcelain';
  chosenTotalCost = porcelainMinTotal;
}

// Combine saved plans and applications into a single view
const financingRecords = [];

savedPlans.forEach(p => {
  if (!p) return;
  financingRecords.push({
    treatment_type: p.treatment_type || null,
    treatment_cost: typeof p.treatment_cost === 'number' ? p.treatment_cost : null,
    interest_rate_percent: typeof p.interest_rate_percent === 'number' ? p.interest_rate_percent : null,
    monthly_payment_value: typeof p.monthly_payment === 'number' ? p.monthly_payment : null
  });
});

apps.forEach(a => {
  if (!a) return;
  financingRecords.push({
    treatment_type: a.treatment_type || null,
    treatment_cost: typeof a.treatment_cost === 'number' ? a.treatment_cost : null,
    interest_rate_percent: typeof a.interest_rate_percent === 'number' ? a.interest_rate_percent : null,
    monthly_payment_value: typeof a.monthly_payment_estimate === 'number' ? a.monthly_payment_estimate : null
  });
});

let qualifyingRecords = [];
if (chosenTotalCost != null) {
  qualifyingRecords = financingRecords.filter(r => {
    if (!r) return false;
    if (r.treatment_type !== 'veneers') return false;
    if (typeof r.treatment_cost !== 'number' || typeof r.monthly_payment_value !== 'number') return false;
    if (Math.abs(r.treatment_cost - chosenTotalCost) > 1e-2) return false;
    if (r.monthly_payment_value >= 150) return false;
    return true;
  });
}

// CP1 (0.6): At least one veneers financing record uses the cheaper eligible material's 4-tooth total cost and has monthly payments under $150
checkpoints.push({ passed: qualifyingRecords.length > 0, weight: 0.6 });

// CP2 (0.4): Among those qualifying records, at least one uses 0% interest
const zeroInterestQualifying = qualifyingRecords.filter(r => r && r.interest_rate_percent === 0);
checkpoints.push({ passed: zeroInterestQualifying.length > 0, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const clinics = JSON.parse(localStorage.getItem('clinics') || '[]');
const emergencies = JSON.parse(localStorage.getItem('emergency_contact_requests') || '[]');

// Determine origin by a clinic in ZIP 94103
let originLat = null;
let originLng = null;
const originClinic = clinics.find(c => c && c.zip === '94103' && typeof c.latitude === 'number' && typeof c.longitude === 'number');
if (originClinic) {
  originLat = originClinic.latitude;
  originLng = originClinic.longitude;
}

function toMiles(lat1, lon1, lat2, lon2) {
  if (typeof lat1 !== 'number' || typeof lon1 !== 'number' || typeof lat2 !== 'number' || typeof lon2 !== 'number') {
    return Number.MAX_SAFE_INTEGER;
  }
  const R = 3958.8;
  const toRad = v => (v * Math.PI) / 180;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
    Math.sin(dLon / 2) * Math.sin(dLon / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

let candidateClinics = [];
if (originLat != null && originLng != null) {
  candidateClinics = clinics
    .map(c => {
      if (!c) return null;
      const dist = toMiles(originLat, originLng, c.latitude, c.longitude);
      return Object.assign({}, c, { distance_miles: dist });
    })
    .filter(c => c && c.open_sunday && c.has_emergency_care && c.distance_miles <= 15);
}

candidateClinics.sort((a, b) => {
  const ad = (typeof a.distance_miles === 'number') ? a.distance_miles : Number.MAX_SAFE_INTEGER;
  const bd = (typeof b.distance_miles === 'number') ? b.distance_miles : Number.MAX_SAFE_INTEGER;
  if (ad !== bd) return ad - bd;
  return (a.name || '').localeCompare(b.name || '');
});

const nearestClinic = candidateClinics[0] || null;

// Emergency requests matching broken tooth and within 2 hours
const brokenToothWithin2h = emergencies.filter(e => e && e.issue_type === 'broken_tooth' && e.preferred_contact_timeframe === 'within_2_hours');

// CP1 (0.7): At least one such request is sent to the nearest qualifying clinic
let sentToNearest = false;
if (nearestClinic) {
  sentToNearest = brokenToothWithin2h.some(e => e.clinic_id === nearestClinic.id);
}
checkpoints.push({ passed: sentToNearest, weight: 0.7 });

// CP2 (0.3): At least one such request is sent to any clinic that is within 15 miles, open Sunday, and has emergency care
const candidateIds = new Set(candidateClinics.map(c => c.id));
const sentToAnyCandidate = brokenToothWithin2h.some(e => candidateIds.has(e.clinic_id));
checkpoints.push({ passed: sentToAnyCandidate, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const dentists = JSON.parse(localStorage.getItem('dentists') || '[]');
const appointments = JSON.parse(localStorage.getItem('appointment_requests') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

let baseline = null;
if (metadata && metadata.baselineDate) {
  const s = metadata.baselineDate;
  baseline = new Date(s + 'T00:00:00');
  if (isNaN(baseline.getTime())) baseline = null;
}

function isWithinNext14Days(dateStr) {
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return false;
  if (!baseline) return true; // if no baseline, don't penalize
  const diffMs = d.getTime() - baseline.getTime();
  if (diffMs < 0) return false;
  const diffDays = diffMs / (1000 * 60 * 60 * 24);
  return diffDays <= 14;
}

// Eligible female cosmetic dentists
const eligibleDentists = dentists.filter(d => {
  if (!d) return false;
  if (d.primary_specialty !== 'cosmetic_dentistry') return false;
  if (d.gender !== 'female') return false;
  if (typeof d.years_experience !== 'number' || d.years_experience < 8) return false;
  if (typeof d.rating_average !== 'number' || d.rating_average < 4.7) return false;
  return d.is_accepting_new_patients !== false;
});

let topDentist = null;
if (eligibleDentists.length > 0) {
  const sorted = eligibleDentists.slice().sort((a, b) => {
    const ar = a.rating_average || 0;
    const br = b.rating_average || 0;
    if (br !== ar) return br - ar;
    const ac = a.rating_count || 0;
    const bc = b.rating_count || 0;
    return bc - ac;
  });
  topDentist = sorted[0];
}

// Appointments for top dentist that match visit type and time constraints
const topAppts = appointments.filter(a => {
  if (!a || !topDentist) return false;
  if (a.dentist_id !== topDentist.id) return false;
  if (a.source_page !== 'dentist_profile') return false;
  if (a.visit_type !== 'in_person_consultation') return false;
  if (!a.requested_datetime) return false;
  const dt = new Date(a.requested_datetime);
  if (isNaN(dt.getTime())) return false;
  const hour = dt.getHours();
  const minute = dt.getMinutes();
  const timeOk = (hour === 10 && minute === 0);
  if (!timeOk) return false;
  return isWithinNext14Days(a.requested_datetime);
});

// CP1 (0.7): Consultation booked with the top-rated qualifying dentist at 10:00 AM within 14 days
checkpoints.push({ passed: topAppts.length > 0, weight: 0.7 });

// CP2 (0.3): Consultation booked with any qualifying female cosmetic dentist at 10:00 AM within 14 days
const dentistMap = new Map(dentists.map(d => [d.id, d]));
const anyEligibleAppt = appointments.some(a => {
  if (!a || !a.dentist_id || !a.requested_datetime) return false;
  const d = dentistMap.get(a.dentist_id);
  if (!d) return false;
  const isEligible = d.primary_specialty === 'cosmetic_dentistry' && d.gender === 'female' && d.years_experience >= 8 && d.rating_average >= 4.7 && d.is_accepting_new_patients !== false;
  if (!isEligible) return false;
  if (a.source_page !== 'dentist_profile' || a.visit_type !== 'in_person_consultation') return false;
  const dt = new Date(a.requested_datetime);
  if (isNaN(dt.getTime())) return false;
  const hour = dt.getHours();
  const minute = dt.getMinutes();
  const timeOk = (hour === 10 && minute === 0);
  if (!timeOk) return false;
  return isWithinNext14Days(a.requested_datetime);
});
checkpoints.push({ passed: anyEligibleAppt, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const sessions = JSON.parse(localStorage.getItem('assessment_sessions') || '[]');
const treatments = JSON.parse(localStorage.getItem('treatments') || '[]');
const estimates = JSON.parse(localStorage.getItem('estimate_requests') || '[]');

// CP1 (0.3): At least one completed assessment session
const completedSessions = sessions.filter(s => s && s.completed_at);
checkpoints.push({ passed: completedSessions.length > 0, weight: 0.3 });

function getCostMax(t) {
  if (!t) return null;
  if (typeof t.price_max === 'number') return t.price_max;
  if (typeof t.price_min === 'number') return t.price_min;
  if (typeof t.price === 'number') return t.price;
  if (typeof t.price_per_unit === 'number') return t.price_per_unit;
  return null;
}

function getDurationMonthsMax(t) {
  if (!t) return null;
  if (typeof t.duration_months_max === 'number') return t.duration_months_max;
  if (typeof t.duration_months_min === 'number') return t.duration_months_min;
  return null;
}

// Eligible treatments from assessment recommendations: active, in assessment, cost <= 2500, duration <= 6 months
const eligibleTreatments = treatments.filter(t => {
  if (!t || t.is_active === false || t.is_in_assessment !== true) return false;
  const costMax = getCostMax(t);
  if (costMax == null || costMax > 2500) return false;
  const durMax = getDurationMonthsMax(t);
  if (durMax != null && durMax > 6) return false;
  return true;
});

let maxRating = 0;
eligibleTreatments.forEach(t => {
  const r = typeof t.patient_satisfaction_rating === 'number' ? t.patient_satisfaction_rating : 0;
  if (r > maxRating) maxRating = r;
});

const bestIds = eligibleTreatments
  .filter(t => (t.patient_satisfaction_rating || 0) === maxRating)
  .map(t => t.id);

const assessmentEstimates = estimates.filter(e => e && e.source === 'smile_assessment');

// CP2 (0.7): An estimate from the smile assessment was requested by email for a treatment that is eligible and has the highest satisfaction rating
const qualifyingEstimate = assessmentEstimates.some(e => {
  if (!e || !e.treatment_id) return false;
  if (!e.email) return false;
  if (bestIds.indexOf(e.treatment_id) === -1) return false;
  return true;
});

checkpoints.push({ passed: qualifyingEstimate, weight: 0.7 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const offers = JSON.parse(localStorage.getItem('offers') || '[]');
const appointments = JSON.parse(localStorage.getItem('appointment_requests') || '[]');

function includesAll(arr, required) {
  if (!Array.isArray(arr)) return false;
  return required.every(x => arr.indexOf(x) !== -1);
}

// Offers that are new-patient, < $199, include exam/x_rays/cleaning, and valid at any time in March 2026
const marchStart = new Date('2026-03-01T00:00:00Z');
const marchEnd = new Date('2026-03-31T23:59:59Z');

function overlapsMarch(o) {
  if (!o || !o.valid_from || !o.valid_to) return false;
  const from = new Date(o.valid_from);
  const to = new Date(o.valid_to);
  if (isNaN(from.getTime()) || isNaN(to.getTime())) return false;
  return from <= marchEnd && to >= marchStart;
}

const candidateOffers = offers.filter(o => {
  if (!o) return false;
  if (o.offer_type !== 'new_patient') return false;
  if (typeof o.price !== 'number' || o.price >= 199) return false;
  if (!includesAll(o.included_services, ['exam', 'x_rays', 'cleaning'])) return false;
  if (!overlapsMarch(o)) return false;
  return true;
});

let chosenOffer = null;
let lowestPrice = null;
if (candidateOffers.length > 0) {
  candidateOffers.forEach(o => {
    const p = o.price;
    if (typeof p !== 'number') return;
    if (lowestPrice == null || p < lowestPrice) {
      lowestPrice = p;
      chosenOffer = o;
    }
  });
}

// Appointments tied to the chosen cheapest qualifying offer
const offerAppointments = appointments.filter(a => {
  if (!a || !chosenOffer) return false;
  if (a.offer_id !== chosenOffer.id) return false;
  return true;
});

// CP1 (0.5): At least one appointment request uses the cheapest qualifying new-patient March offer under $199
checkpoints.push({ passed: offerAppointments.length > 0, weight: 0.5 });

// CP2 (0.5): Among those, at least one appointment is on a Tuesday in March 2026 at 9:00 AM
const hasTuesday9amMarch = offerAppointments.some(a => {
  if (!a || !a.requested_datetime) return false;
  const dt = new Date(a.requested_datetime);
  if (isNaN(dt.getTime())) return false;
  const year = dt.getFullYear();
  const month = dt.getMonth(); // 0-based; 2 = March
  const dayOfWeek = dt.getDay(); // 2 = Tuesday
  const hour = dt.getHours();
  const minute = dt.getMinutes();
  return year === 2026 && month === 2 && dayOfWeek === 2 && hour === 9 && minute === 0;
});
checkpoints.push({ passed: hasTuesday9amMarch, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const apps = JSON.parse(localStorage.getItem('financing_applications') || '[]');

// Applications for Invisalign, cost 4800, 0% interest, with monthly payment <= 200 and reasonable term
const qualifyingApps = apps.filter(a => {
  if (!a) return false;
  if (a.treatment_type !== 'invisalign') return false;
  if (typeof a.treatment_cost !== 'number' || Math.abs(a.treatment_cost - 4800) > 1e-2) return false;
  if (!a.is_zero_interest || a.interest_rate_percent !== 0) return false;
  if (typeof a.monthly_payment_estimate !== 'number') return false;
  if (a.monthly_payment_estimate > 200) return false;
  if (typeof a.term_months !== 'number' || a.term_months < 24) return false;
  return true;
});

// CP1 (0.6): At least one submitted financing application matches a 0% interest Invisalign plan for $4,800 with monthly payments <= $200 and term >= 24 months
checkpoints.push({ passed: qualifyingApps.length > 0, weight: 0.6 });

// CP2 (0.4): Among those, at least one records a desired monthly payment close to $200
const hasDesired200 = qualifyingApps.some(a => {
  if (typeof a.desired_monthly_payment !== 'number') return false;
  return Math.abs(a.desired_monthly_payment - 200) <= 0.5;
});
checkpoints.push({ passed: hasDesired200, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const cases = JSON.parse(localStorage.getItem('smile_gallery_cases') || '[]');
const favoritesArr = JSON.parse(localStorage.getItem('favorites') || '[]');
const inquiries = JSON.parse(localStorage.getItem('case_inquiries') || '[]');
const state = JSON.parse(localStorage.getItem('single_user_state') || '{}');

// Filter gallery to composite bonding, front teeth, 1–2 visits
const filteredCases = cases.filter(c => {
  if (!c) return false;
  if (c.treatment_type !== 'composite_bonding') return false;
  if (c.tooth_area !== 'front_teeth') return false;
  if (typeof c.number_of_visits !== 'number') return false;
  return c.number_of_visits >= 1 && c.number_of_visits <= 2;
});

const filteredIds = filteredCases.map(c => c.id);
const firstId = filteredIds[0];
const secondId = filteredIds[1];

let favoritesList = null;
if (state && state.favorites_list_id) {
  favoritesList = favoritesArr.find(l => l && l.id === state.favorites_list_id) || null;
}
if (!favoritesList && favoritesArr.length > 0) {
  favoritesList = favoritesArr[0];
}

const favoriteCaseIds = (favoritesList && Array.isArray(favoritesList.case_ids)) ? favoritesList.case_ids : [];

// CP1 (0.6): Favorites include the first two filtered composite bonding cases
let hasFirstTwo = false;
if (firstId && secondId) {
  hasFirstTwo = favoriteCaseIds.includes(firstId) && favoriteCaseIds.includes(secondId);
}
checkpoints.push({ passed: hasFirstTwo, weight: 0.6 });

// CP2 (0.4): A case inquiry was submitted for the second of those filtered cases
let inquiryForSecond = false;
if (secondId) {
  inquiryForSecond = inquiries.some(i => i && i.case_id === secondId);
}
checkpoints.push({ passed: inquiryForSecond, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
